/* ===== admin/core.min.js ===== */
var ATP_API='https://atpworldweb-production.up.railway.app/api';function getToken(){return localStorage.getItem('atp_token')||'';}
function apiGet(path){return fetch(ATP_API+path,{headers:{'Authorization':'Bearer '+getToken()}}).then(function(r){return r.json();});}
function apiPost(path,body){return fetch(ATP_API+path,{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+getToken()},body:JSON.stringify(body)}).then(function(r){return r.json();});}
var ADMIN_CREDENTIALS={user:'atpadmin',pass:'atp2015!'};var adminLoggedIn=false;function adminLogin(){var u=document.getElementById('adminUser').value.trim();var p=document.getElementById('adminPass').value;var errEl=document.getElementById('loginErr');errEl.style.display='none';if(!u||!p){errEl.textContent='Please enter email and password';errEl.style.display='block';return;}
fetch('https://atpworldweb-production.up.railway.app/api/auth/login',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({email:u,password:p})}).then(function(r){return r.json();}).then(function(data){if(data.token&&data.member&&data.member.is_admin){localStorage.setItem('atp_token',data.token);document.getElementById('loginScreen').style.display='none';document.getElementById('adminWrap').style.display='block';var LOGO='/atp-logo-transparent.png';document.querySelectorAll('#adminLogo,#adminLogoNav').forEach(function(img){img.src=LOGO;img.style.filter='none';});loadDashboardAPI();loadMembersAPI();loadCities();loadCoaches();loadTribes();loadDashboardWidgets&&loadDashboardWidgets();}else if(data.token&&data.member&&!data.member.is_admin){errEl.textContent='Account found but does not have admin access.';errEl.style.display='block';}else{errEl.textContent=data.error||'Invalid email or password.';errEl.style.display='block';}}).catch(function(){errEl.textContent='Connection error — please try again.';errEl.style.display='block';});}
function adminLogout(){adminLoggedIn=false;document.getElementById('adminWrap').style.display='none';document.getElementById('loginScreen').style.display='flex';document.getElementById('adminUser').value='';document.getElementById('adminPass').value='';}
document.getElementById('adminPass').addEventListener('keydown',function(e){if(e.key==='Enter')adminLogin();});function showAdminSection(name,btn){if(name==='sessions'){loadCities();loadCoaches();loadTribes();setTimeout(loadSessionsList,300);}
['dashboard','members','ambassadors','sessions','challenges','coaches','analytics','content'].forEach(function(s){document.getElementById('section-'+s).style.display='none';});document.getElementById('section-'+name).style.display='block';document.querySelectorAll('.admin-nav-item').forEach(function(b){b.classList.remove('active');});if(btn)btn.classList.add('active');else{document.querySelectorAll('.admin-nav-item').forEach(function(b){if(b.textContent.toLowerCase().includes(name))b.classList.add('active');});}
if(name==='members')loadMembersAPI();if(name==='ambassadors')loadAmbassadorsAPI();if(name==='dashboard'){loadDashboardAPI();loadDashboardWidgets&&loadDashboardWidgets();}}
var MEMBERS_DATA=[];var CHALLENGES_DATA=[{icon:'🏃',name:'July Run Challenge',type:'monthly',metric:'Sessions attended',target:8,desc:'Complete 8 running sessions this month',active:true,participants:127},{icon:'🔥',name:'Bootcamp Blitz',type:'weekly',metric:'Sessions attended',target:4,desc:'Attend 4 bootcamp sessions in 2 weeks',active:true,participants:89},];
/* ===== admin/members.min.js ===== */
function renderMembers(filter){loadMembersAPI(filter);return;var list=MEMBERS_DATA;if(filter){var q=filter.toLowerCase();list=list.filter(function(m){return m.name.toLowerCase().includes(q)||m.id.toLowerCase().includes(q)||m.email.toLowerCase().includes(q);});}
document.getElementById('membersTbody').innerHTML=list.map(function(m){return'<tr>'+'<td style="display:flex;align-items:center"><div class="admin-av">'+m.name[0]+'</div><div><div class="admin-member-name">'+m.name+'</div><div class="admin-member-email">'+m.id+' · '+m.email+'</div></div></td>'+'<td style="color:#555;font-size:12px">'+m.joined+'</td>'+'<td style="color:#fff;font-size:13px;font-weight:600">'+m.sessions+'</td>'+'<td><span class="badge '+(m.active?'badge-green':'badge-grey')+'">'+(m.active?'Active':'Inactive')+'</span></td>'+'<td><button class="admin-btn" onclick="makeAmbassador(\''+m.id+'\')">Make Ambassador</button></td>'+'</tr>';}).join('');}
var _searchTimer=null;function filterMembers(q){clearTimeout(_searchTimer);_searchTimer=setTimeout(function(){var token=getToken();if(token&&q&&q.length>1){var url='https://atpworldweb-production.up.railway.app/api/admin/members?limit=50&search='+encodeURIComponent(q);fetch(url,{headers:{'Authorization':'Bearer '+token}}).then(function(r){return r.json();}).then(function(data){if(!data.members)return;var tbody=document.getElementById('membersTbody');if(!tbody)return;if(!data.members.length){tbody.innerHTML='<tr><td colspan="5" style="text-align:center;color:#444;padding:24px">No members found for "'+q+'"</td></tr>';return;}
tbody.innerHTML=data.members.map(function(m){var name=((m.first_name||'')+' '+(m.last_name||'')).trim();var ini=((m.first_name||'?')[0]+(m.last_name||'?')[0]).toUpperCase();var joined=m.joined_at?new Date(m.joined_at).toLocaleDateString('en-GB',{month:'short',year:'numeric'}):'—';return'<tr>'+'<td style="display:flex;align-items:center;gap:10px"><div class="admin-av">'+ini+'</div>'+'<div><div class="admin-member-name">'+name+'</div>'+'<div class="admin-member-email">'+m.member_number+' · '+m.email+'</div></div></td>'+'<td style="color:#555;font-size:12px">'+joined+'</td>'+'<td style="color:#fff;font-size:13px;font-weight:600">'+(m.sessions_count||0)+'</td>'+'<td><span class="badge '+(m.is_banned?'badge-grey':'badge-green')+'">'+(m.is_banned?'Inactive':'Active')+'</span></td>'+'<td><button class="admin-btn" onclick="makeAmbassador(this.dataset.mid)" data-mid="'+m.id+'">Make Ambassador</button></td>'+'</tr>';}).join('');var lbl=document.querySelector('.admin-section-title span');if(lbl)lbl.textContent=data.total.toLocaleString()+' total · showing '+data.members.length+' results';}).catch(function(){});}else if(!q||!q.length){loadMembersAPI();}else{renderMembers(q);}},350);}
/* ===== admin/ambassadors.min.js ===== */
async function loadAmbassadorsAPI(){return renderAmbassadors();}
async function renderAmbassadors(){var tbody=document.getElementById('ambassadorTbody');if(!tbody)return;tbody.innerHTML='<tr><td colspan="5" style="text-align:center;color:#444;padding:20px">Loading…</td></tr>';try{var data=await apiGet('/admin/members?is_ambassador=true&limit=200');var ambs=data.members||[];if(!ambs.length){tbody.innerHTML='<tr><td colspan="5" style="text-align:center;color:#444;padding:20px">No ambassadors yet — go to Members and activate some</td></tr>';return;}
tbody.innerHTML=ambs.map(function(m){var name=((m.first_name||'')+' '+(m.last_name||'')).trim();var ini=((m.first_name||'?')[0]+(m.last_name||'?')[0]).toUpperCase();var joined=m.joined_at?new Date(m.joined_at).toLocaleDateString('en-GB',{month:'short',year:'numeric'}):'—';var coachBtn=m.is_coach?'<button class="admin-btn" style="font-size:11px;padding:4px 10px;background:#0d1a0a;color:#7AC231;border-color:#7AC231;margin-right:6px" onclick="toggleCoach(this.dataset.mid,false)" data-mid="'+m.id+'">🎽 Remove Coach</button>':'<button class="admin-btn" style="font-size:11px;padding:4px 10px;margin-right:6px" onclick="toggleCoach(this.dataset.mid,true)" data-mid="'+m.id+'">🎽 Make Coach</button>';return'<tr>'+'<td style="display:flex;align-items:center;gap:10px"><div class="admin-av" style="background:rgba(255,196,0,.15);color:#ffc400">'+ini+'</div><div><div class="admin-member-name">'+name+'</div><div class="admin-member-email">'+m.member_number+' · '+m.email+'</div></div></td>'+'<td style="color:#555;font-size:12px">'+joined+'</td>'+'<td style="color:#7AC231;font-weight:700">'+(m.sessions_count||0)+' sessions</td>'+'<td><span class="badge badge-green">Active</span>'+(m.is_coach?' <span class="badge" style="background:#0d1a0a;color:#7AC231;border:1px solid #7AC231">🎽 Coach</span>':'')+'</td>'+'<td>'+coachBtn+'<button class="admin-btn admin-btn-danger" onclick="removeAmbassador(this.dataset.mid)" data-mid="'+m.id+'" style="font-size:11px;padding:4px 10px">Revoke</button></td>'+'</tr>';}).join('');}catch(e){tbody.innerHTML='<tr><td colspan="5" style="text-align:center;color:#f87171;padding:20px">Error: '+e.message+'</td></tr>';}}
function showAddAmbassador(){var form=document.getElementById('addAmbForm');if(form){form.style.display='block';form.scrollIntoView({behavior:'smooth'});}}
async function addAmbassador(){var input=document.getElementById('newAmbInput').value.trim();if(!input){showToast('⚠️ Please enter member ID or email',true);return;}
var token=getToken();try{var search=await fetch(ATP_API+'/admin/members?search='+encodeURIComponent(input),{headers:{'Authorization':'Bearer '+token}}).then(r=>r.json());if(!search.members||!search.members.length){showToast('❌ Member not found',true);return;}
var member=search.members[0];var res=await fetch(ATP_API+'/admin/members/'+member.id+'/ambassador',{method:'PATCH',headers:{'Content-Type':'application/json','Authorization':'Bearer '+token},body:JSON.stringify({enabled:true})}).then(r=>r.json());if(res.message||res.success){showToast('✅ '+member.first_name+' is now an Ambassador!');document.getElementById('newAmbInput').value='';document.getElementById('addAmbForm').style.display='none';setTimeout(function(){renderAmbassadors();loadMembersAPI&&loadMembersAPI();loadCoachesSection&&loadCoachesSection();},300);}else{showToast('❌ '+(res.error||'Failed'),true);}}catch(e){showToast('❌ '+e.message,true);}}
function toggleAmbassador(id,enabled){var m=MEMBERS_DATA.find(function(x){return x.id===id;});if(m)m.ambassadorActive=enabled;showAdminToast((enabled?'✓ Ambassador activated':'Ambassador deactivated')+' for '+m.name);renderAmbassadors();var stored=null;try{stored=JSON.parse(localStorage.getItem('atp:user'));}catch(e){}
if(stored&&stored.email===m.email){localStorage.setItem('atp:ambassador',enabled?'true':'false');}}
function revokeAmbassador(id){var m=MEMBERS_DATA.find(function(x){return x.id===id;});if(!m||!confirm('Revoke ambassador access for '+m.name+'?'))return;m.ambassador=false;m.ambassadorActive=false;showAdminToast('Ambassador access revoked for '+m.name,'warn');renderAmbassadors();}
/* ===== admin/sessions.min.js ===== */
async function loadCities(){var sel=document.getElementById('sCity');if(!sel)return;sel.innerHTML='<option value="">Select city...</option>';try{var token=getToken();var data=await fetch('https://atpworldweb-production.up.railway.app/api/sessions?limit=1',{headers:{'Authorization':'Bearer '+token}}).then(function(r){return r.json();});var cities=['Dubai','Al Ain','Muscat'];cities.forEach(function(c){var o=document.createElement('option');o.value=c;o.textContent=c;sel.appendChild(o);});}catch(e){['Dubai','Al Ain','Muscat'].forEach(function(c){var o=document.createElement('option');o.value=c;o.textContent=c;sel.appendChild(o);});}
var dt=document.getElementById('sDate');if(dt){var d=new Date();d.setDate(d.getDate()+1);d.setHours(19,0,0,0);var pad=function(n){return n<10?'0'+n:n;};dt.value=d.getFullYear()+'-'+pad(d.getMonth()+1)+'-'+pad(d.getDate())+'T'+pad(d.getHours())+':'+pad(d.getMinutes());}}
function toggleLive(){var cb=document.getElementById('sLiveEnabled');var toggle=document.getElementById('sLiveToggle');var knob=document.getElementById('sLiveKnob');cb.checked=!cb.checked;if(cb.checked){toggle.style.background='#7AC231';toggle.style.borderColor='#7AC231';knob.style.left='22px';knob.style.background='#fff';}else{toggle.style.background='#1a1a1a';toggle.style.borderColor='#333';knob.style.left='2px';knob.style.background='#444';}}
var ALL_CITIES=[];var SESSIONS_CACHE={};var SESSION_EDIT_ID=null;var SPORT_LEVELS={padel:['Beginner','Level D+','Level C-','Level C+','Level B'],football:['Beginner','Intermediate','Advanced'],volleyball:['Beginner','Intermediate','Advanced'],badminton:['Beginner','Intermediate','Advanced'],basketball:['Beginner','Intermediate','Advanced'],};function selectCategory(cat){document.querySelectorAll('.session-cat-btn').forEach(function(b){b.classList.remove('active');});document.querySelector('[data-cat="'+cat+'"]').classList.add('active');document.getElementById('teamSportsSection').style.display=cat==='team_sports'?'block':'none';if(cat==='team_sports')buildCourtsUI();}
function updateDayTimes(){var container=document.getElementById('dayTimesContainer');var checked=Array.from(document.querySelectorAll('.day-check-btn input:checked')).map(function(i){return i.value;});container.innerHTML=checked.map(function(day){return'<div style="display:flex;align-items:center;gap:8px;background:#1a1a1a;border:1px solid #2a2a2a;border-radius:8px;padding:8px 12px">'+'<span style="font-size:12px;font-weight:700;color:#7AC231;min-width:32px">'+day+'</span>'+'<input class="admin-form-input" type="time" id="time-'+day+'" value="06:30" style="width:100px;padding:4px 8px">'+'</div>';}).join('');}
function filterCitiesByCountry(){var country=document.getElementById('sCountry').value;var cityEl=document.getElementById('sCity');cityEl.innerHTML='<option value="">Select City</option>';var filtered=ALL_CITIES.filter(function(c){return!country||c.country===country;});var seen={};filtered=filtered.filter(function(c){if(seen[c.name])return false;seen[c.name]=true;return true;});filtered.forEach(function(c){cityEl.innerHTML+='<option value="'+c.id+'">'+c.name+'</option>';});var filterEl=document.getElementById('filterCity');if(filterEl){filterEl.innerHTML='<option value="">All Cities</option>';ALL_CITIES.forEach(function(c){filterEl.innerHTML+='<option value="'+c.id+'">'+c.name+'</option>';});}}
async function loadCities(){try{var data=await apiGet('/cities');ALL_CITIES=data.cities||[];filterCitiesByCountry();}catch(e){console.warn('Cities load error:',e.message);}}
async function loadCoaches(){try{var data=await apiGet('/admin/members?is_coach=true&limit=200');var coachEl=document.getElementById('sCoach');if(!coachEl)return;coachEl.innerHTML='<option value="">No coach assigned</option>';(data.members||[]).forEach(function(m){coachEl.innerHTML+='<option value="'+m.id+'">'+m.first_name+' '+m.last_name+'</option>';});}catch(e){console.warn('Coaches load error:',e.message);}}
async function loadTribes(){try{var res=await fetch(ATP_API+'/sessions/tribes');var data=await res.json();var tribeEl=document.getElementById('sTribe');if(!tribeEl)return;tribeEl.innerHTML='<option value="">No tribe</option>';(data.tribes||[]).forEach(function(t){tribeEl.innerHTML+='<option value="'+t.id+'">'+t.name+' Tribe</option>';});}catch(e){console.warn('Tribes load error:',e.message);}}
function updateSportLevels(){buildCourtsUI();}
function buildCourtsUI(){var sport=document.getElementById('sSport').value;var numCourts=parseInt(document.getElementById('sNumCourts').value)||1;var levels=SPORT_LEVELS[sport]||['Beginner','Intermediate','Advanced'];var container=document.getElementById('courtsContainer');container.innerHTML='';for(var i=1;i<=numCourts;i++){var levOpts=levels.map(function(l){return'<option value="'+l+'">'+l+'</option>';}).join('');container.innerHTML+='<div class="court-card">'+'<div class="court-card-header">Court '+i+'</div>'+'<div style="display:flex;gap:10px;flex-wrap:wrap">'+'<div class="admin-form-group" style="flex:1;min-width:150px">'+'<label class="admin-form-label">Court Name</label>'+'<input class="admin-form-input" type="text" id="court-name-'+i+'" placeholder="e.g. Court '+i+'" value="Court '+i+'">'+'</div>'+'<div class="admin-form-group" style="flex:1;min-width:150px">'+'<label class="admin-form-label">Level Allowed</label>'+'<select class="admin-form-select" id="court-level-'+i+'">'+levOpts+'</select>'+'</div>'+'<div class="admin-form-group" style="flex:1;min-width:120px">'+'<label class="admin-form-label">Players per Court</label>'+'<input class="admin-form-input" type="number" id="court-players-'+i+'" value="4" min="2" max="20">'+'</div>'+'</div>'+'</div>';}}
function getCourtsData(){var sport=document.getElementById('sSport').value;var numCourts=parseInt(document.getElementById('sNumCourts').value)||1;var courts=[];for(var i=1;i<=numCourts;i++){courts.push({court_number:i,name:(document.getElementById('court-name-'+i)||{}).value||('Court '+i),level:(document.getElementById('court-level-'+i)||{}).value||'Beginner',max_players:parseInt((document.getElementById('court-players-'+i)||{}).value)||4,});}
return courts;}
function buildRepeatDates(days,startDate,endDate,times){if(!days.length||!startDate)return null;var dayMap={Mon:1,Tue:2,Wed:3,Thu:4,Fri:5,Sat:6,Sun:0};var dates=[];var start=new Date(startDate);var end=endDate?new Date(endDate):new Date(startDate);if(!endDate){days.forEach(function(day){var d=new Date(start);var target=dayMap[day];var diff=(target-d.getDay()+7)%7;if(diff===0)diff=0;d.setDate(d.getDate()+diff);var time=times[day]||'06:30';d.setHours(parseInt(time.split(':')[0]),parseInt(time.split(':')[1]),0,0);dates.push(d.toISOString());});}else{var current=new Date(start);while(current<=end){var dayName=['Sun','Mon','Tue','Wed','Thu','Fri','Sat'][current.getDay()];if(days.indexOf(dayName)!==-1){var d=new Date(current);var time=times[dayName]||'06:30';d.setHours(parseInt(time.split(':')[0]),parseInt(time.split(':')[1]),0,0);dates.push(d.toISOString());}
current.setDate(current.getDate()+1);}}
return dates;}
function editSessionById(id){var s=SESSIONS_CACHE[id];if(s)editSession(s);}
async function cancelSessionById(id){var s=SESSIONS_CACHE[id];if(!s)return;if(!confirm('Cancel "'+s.name+'"? All registered members will be notified.'))return;var reason=prompt('Reason (optional):','Session cancelled by admin')||'';try{var token=getToken();var res=await fetch(ATP_API+'/sessions/'+id+'/cancel',{method:'PATCH',headers:{'Content-Type':'application/json','Authorization':'Bearer '+token},body:JSON.stringify({reason})});var d=await res.json();if(d.session){showToast('✅ Session cancelled');loadSessionsList();}
else showToast('❌ '+(d.error||'Failed'),true);}catch(e){showToast('❌ '+e.message,true);}}
async function cancelSeriesByName(){var s=prompt('Enter exact session name to cancel ALL upcoming occurrences:');if(!s)return;if(!confirm('This will cancel ALL future "'+s+'" sessions. Continue?'))return;var reason=prompt('Reason:')||'Series cancelled by admin';try{var token=getToken();var res=await fetch(ATP_API+'/sessions/series/cancel',{method:'PATCH',headers:{'Content-Type':'application/json','Authorization':'Bearer '+token},body:JSON.stringify({name:s,reason})});var d=await res.json();showToast('✅ Cancelled '+(d.cancelled||0)+' sessions');loadSessionsList();}catch(e){showToast('❌ '+e.message,true);}}
async function createSession(){var msgEl=document.getElementById('sessionFormMsg');var isEdit=!!SESSION_EDIT_ID;var name=document.getElementById('sName').value.trim();var city_id=document.getElementById('sCity').value;var location=document.getElementById('sLoc').value.trim();var duration=parseInt(document.getElementById('sDuration').value)||60;var capacity=parseInt(document.getElementById('sCap').value)||30;var points=parseInt(document.getElementById('sPoints').value)||10;var stype=document.getElementById('sType').value;var desc=document.getElementById('sDesc').value.trim();var maps=document.getElementById('sMaps').value.trim();var live=document.getElementById('sLiveEnabled').checked;var coach_id=document.getElementById('sCoach').value||null;var tribe_id=document.getElementById('sTribe').value||null;var cat=(document.querySelector('.session-cat-btn.active')||{}).dataset?.cat||'regular';var sport=document.getElementById('sSport').value||null;if(!name||!city_id||!location){msgEl.textContent='⚠️ Session Name, City and Location are required.';msgEl.style.cssText='display:block;background:#2a1010;color:#f87171;padding:10px 14px;border-radius:8px;margin-bottom:16px;font-size:13px';return;}
var days=Array.from(document.querySelectorAll('.day-check-btn input:checked')).map(function(i){return i.value;});var startDate=document.getElementById('sStartDate').value;var endDate=document.getElementById('sEndDate').value;if(!days.length&&!isEdit){msgEl.textContent='⚠️ Please select at least one day.';msgEl.style.cssText='display:block;background:#2a1010;color:#f87171;padding:10px 14px;border-radius:8px;margin-bottom:16px;font-size:13px';return;}
var times={};days.forEach(function(day){var el=document.getElementById('time-'+day);times[day]=el?el.value:'06:30';});var repeat_dates=null;if(!isEdit){repeat_dates=buildRepeatDates(days,startDate||new Date().toISOString().split('T')[0],endDate,times);if(!repeat_dates||!repeat_dates.length){msgEl.textContent='⚠️ Please set a start date and select at least one day.';msgEl.style.cssText='display:block;background:#2a1010;color:#f87171;padding:10px 14px;border-radius:8px;margin-bottom:16px;font-size:13px';return;}}
var courts=cat==='team_sports'?getCourtsData():null;var scheduled_at=repeat_dates?repeat_dates[0]:document.getElementById('sEditDate')?.value;var payload={name,tribe_id,city_id,description:desc,coach_id,location,location_maps_url:maps,session_type:stype,capacity,scheduled_at,duration_mins:duration,points_reward:points,is_live_enabled:live,session_category:cat,sport_type:sport,courts,repeat_dates:repeat_dates&&repeat_dates.length>1?repeat_dates:null,};var btnLabel=document.getElementById('sessionSubmitLabel');var origLabel=btnLabel.textContent;btnLabel.textContent='⏳ Saving...';try{var token=getToken();var url=isEdit?'https://atpworldweb-production.up.railway.app/api/sessions/'+SESSION_EDIT_ID:'https://atpworldweb-production.up.railway.app/api/sessions';var method=isEdit?'PUT':'POST';var res=await fetch(url,{method,headers:{'Content-Type':'application/json','Authorization':'Bearer '+token},body:JSON.stringify(payload)});var data=await res.json();if(data.sessions||data.session){var count=data.sessions?data.sessions.length:1;msgEl.textContent=isEdit?'✅ Session updated!':'✅ '+count+' session(s) created!';msgEl.style.cssText='display:block;background:#0d1a0a;color:#7AC231;padding:10px 14px;border-radius:8px;margin-bottom:16px;font-size:13px';resetSessionForm();setTimeout(function(){loadSessionsList();loadDashboardAPI();},800);}else{throw new Error(data.error||'Failed to save session');}}catch(e){msgEl.textContent='❌ '+e.message;msgEl.style.cssText='display:block;background:#2a1010;color:#f87171;padding:10px 14px;border-radius:8px;margin-bottom:16px;font-size:13px';}finally{btnLabel.textContent=origLabel;}}
function resetSessionForm(){SESSION_EDIT_ID=null;document.getElementById('sEditId').value='';document.getElementById('sName').value='';document.getElementById('sDesc').value='';document.getElementById('sLoc').value='';document.getElementById('sMaps').value='';document.getElementById('sCity').value='';document.getElementById('sCountry').value='';document.getElementById('sStartDate').value='';document.getElementById('sEndDate').value='';document.querySelectorAll('.day-check-btn input').forEach(function(cb){cb.checked=false;});document.getElementById('dayTimesContainer').innerHTML='';selectCategory('regular');document.getElementById('sessionFormTitle').textContent='Create New Session';document.getElementById('sessionSubmitLabel').textContent='＋ Create Session';document.getElementById('cancelEditBtn').style.display='none';}
function cancelEditSession(){resetSessionForm();}
function editSession(s){SESSION_EDIT_ID=s.id;document.getElementById('sName').value=s.name||'';document.getElementById('sDesc').value=s.description||'';document.getElementById('sLoc').value=s.location||'';document.getElementById('sMaps').value=s.location_maps_url||'';document.getElementById('sDuration').value=s.duration_mins||60;document.getElementById('sCap').value=s.capacity||30;document.getElementById('sPoints').value=s.points_reward||10;document.getElementById('sType').value=s.session_type||'free';if(s.coach_id)document.getElementById('sCoach').value=s.coach_id;if(s.tribe_id)document.getElementById('sTribe').value=s.tribe_id;var cityObj=ALL_CITIES.find(function(c){return c.id===s.city_id;});if(cityObj){document.getElementById('sCountry').value=cityObj.country||'UAE';filterCitiesByCountry();document.getElementById('sCity').value=s.city_id;}
selectCategory(s.session_category||'regular');if(s.sport_type)document.getElementById('sSport').value=s.sport_type;if(s.courts){document.getElementById('sNumCourts').value=s.courts.length;buildCourtsUI();}
document.getElementById('sessionFormTitle').textContent='Edit Session';document.getElementById('sessionSubmitLabel').textContent='✓ Save Changes';document.getElementById('cancelEditBtn').style.display='inline-block';document.getElementById('sessionFormSection').scrollIntoView({behavior:'smooth'});}
async function loadSessionsList(){var tbody=document.getElementById('sessionsTbody');var countEl=document.getElementById('sessionsCountLabel');if(!tbody)return;var cityF=(document.getElementById('filterCity')||{}).value||'';var catF=(document.getElementById('filterCategory')||{}).value||'';var statusF=(document.getElementById('filterStatus')||{}).value||'upcoming';var searchF=(document.getElementById('filterSearch')||{}).value||'';tbody.innerHTML='<tr><td colspan="7" style="text-align:center;color:#444;padding:24px">Loading...</td></tr>';try{var params='limit=100';if(cityF)params+='&city_id='+cityF;if(statusF)params+='&status='+statusF;var data=await apiGet('/sessions?'+params);var sessions=(data.sessions||[]);if(catF)sessions=sessions.filter(function(s){return s.session_category===catF;});if(searchF){var q=searchF.toLowerCase();sessions=sessions.filter(function(s){return(s.name||'').toLowerCase().includes(q)||(s.location||'').toLowerCase().includes(q);});}
if(countEl)countEl.textContent=sessions.length+' sessions';if(!sessions.length){tbody.innerHTML='<tr><td colspan="7" style="text-align:center;color:#444;padding:24px">No sessions found</td></tr>';return;}
var catIcon={regular:'🏃',social:'🎉',team_sports:'🏆'};var catLabel={regular:'Regular',social:'Social',team_sports:'Team Sports'};tbody.innerHTML=sessions.forEach(function(s){SESSIONS_CACHE[s.id]=s;});tbody.innerHTML=sessions.map(function(s){var dt=s.scheduled_at?new Date(s.scheduled_at):null;var dateStr=dt?dt.toLocaleDateString('en-GB',{day:'2-digit',month:'short',year:'numeric'})+' '+dt.toLocaleTimeString('en-GB',{hour:'2-digit',minute:'2-digit'}):'—';var cat=s.session_category||'regular';var sportIcons={padel:'🎾',football:'⚽',volleyball:'🏐',badminton:'🏸',basketball:'🏀'};var sportBadge='';if(cat==='team_sports'&&s.sport_type){var courtsArr=s.courts;if(typeof courtsArr==='string'){try{courtsArr=JSON.parse(courtsArr);}catch(e){courtsArr=[];}}
var courtCount=Array.isArray(courtsArr)?courtsArr.length:0;sportBadge='<div style="font-size:11px;color:#7AC231;margin-top:3px;font-weight:600">'+(sportIcons[s.sport_type]||'🏆')+' '+s.sport_type.charAt(0).toUpperCase()+s.sport_type.slice(1);if(courtCount)sportBadge+=' · '+courtCount+' court'+(courtCount>1?'s':'');sportBadge+='</div>';}
var statusBadge=s.status==='completed'?'<span class="badge badge-grey">Completed</span>':'<span class="badge badge-green">Upcoming</span>';return'<tr>'+'<td><div class="admin-member-name">'+s.name+'</div><div class="admin-member-email">'+(s.location||'')+'</div>'+sportBadge+'</td>'+'<td><span style="font-size:16px">'+catIcon[cat]+'</span> <span style="font-size:12px;color:#888">'+catLabel[cat]+'</span></td>'+'<td style="font-size:12px;color:#888">'+(s.city_name||'—')+'</td>'+'<td style="font-size:12px">'+dateStr+'</td>'+'<td style="font-size:13px">'+(s.checkins_count||0)+' / '+(s.capacity||'?')+'</td>'+'<td style="font-size:12px;color:#888">'+(s.coach_name||'—')+'</td>'+'<td style="white-space:nowrap">'+'<button class="admin-btn" style="font-size:11px;padding:4px 8px;margin-right:3px" onclick="editSessionById(\''+s.id+'\')" title="Edit">✏️</button>'+'<button class="admin-btn" style="font-size:11px;padding:4px 8px;margin-right:3px" onclick="viewRegistrations(\''+s.id+'\')" title="Registrations">'+'👥 '+(s.registrations_count||0)+'</button>'+
(s.status!=='cancelled'?'<button class="admin-btn" style="font-size:11px;padding:4px 8px;color:#f87171;border-color:#3a1a1a" onclick="cancelSession(\''+s.id+'\',\''+(s.name||'session').replace(/\'/g,'')+'\')" title="Cancel session">✕</button>':'<span class="badge badge-grey">Cancelled</span>')+'</td>'+'</tr>';}).join('');}catch(e){tbody.innerHTML='<tr><td colspan="7" style="text-align:center;color:#f87171;padding:24px">Error: '+e.message+'</td></tr>';}}
async function viewRegistrations(sessionId){var s=SESSIONS_CACHE[sessionId]||{};var sessionName=s.name||'Session';var modal=document.getElementById('registrationsModal');var body=document.getElementById('regModalBody');var title=document.getElementById('regModalTitle');title.textContent='👥 '+sessionName;modal.style.display='flex';body.innerHTML='<div style="text-align:center;color:#444;padding:24px">Loading...</div>';try{var token=getToken();var res=await fetch('https://atpworldweb-production.up.railway.app/api/sessions/'+sessionId+'/registrations',{headers:{'Authorization':'Bearer '+token}});var data=await res.json();var regs=data.registrations||[];if(!regs.length){body.innerHTML='<div style="text-align:center;color:#444;padding:24px">No registrations yet</div>';return;}
var courtsSummary='';var courtsArr=s?s.courts:null;if(typeof courtsArr==='string'){try{courtsArr=JSON.parse(courtsArr);}catch(e){courtsArr=[];}}
if(s&&s.session_category==='team_sports'&&Array.isArray(courtsArr)&&courtsArr.length){var grouped={};regs.forEach(function(r){var court=r.court_name||'Unassigned';if(!grouped[court])grouped[court]=0;grouped[court]++;});courtsSummary='<div style="background:#111;border-radius:10px;padding:12px;margin-bottom:14px;display:grid;grid-template-columns:repeat(auto-fit,minmax(140px,1fr));gap:8px">';courtsArr.forEach(function(ct){var count=grouped[ct.name]||0;var pct=Math.round((count/(ct.max_players||4))*100);courtsSummary+='<div style="padding:10px;background:#1a1a1a;border-radius:8px;border-left:3px solid #7AC231">'+'<div style="font-size:12px;font-weight:700;color:#fff">'+ct.name+'</div>'+'<div style="font-size:10px;color:#7AC231;margin-top:2px">'+ct.level+'</div>'+'<div style="font-size:14px;color:#fff;margin-top:6px;font-weight:700">'+count+' / '+ct.max_players+'</div>'+'<div style="height:3px;background:#2a2a2a;border-radius:2px;margin-top:4px"><div style="width:'+pct+'%;height:100%;background:#7AC231;border-radius:2px"></div></div>'+'</div>';});courtsSummary+='</div>';}
body.innerHTML=courtsSummary+'<div style="font-size:12px;color:#888;margin-bottom:12px">'+regs.length+' registered</div>'+'<table class="admin-table" style="width:100%"><thead><tr><th>Member</th><th>Member #</th><th>Level</th><th>Court</th><th>Status</th></tr></thead><tbody>'+
regs.map(function(r){return'<tr>'+'<td><div class="admin-member-name">'+r.first_name+' '+r.last_name+'</div><div class="admin-member-email">'+r.email+'</div></td>'+'<td style="font-size:12px;color:#888">'+r.member_number+'</td>'+'<td style="font-size:12px;color:#888">'+(r.padel_level||'—')+'</td>'+'<td style="font-size:12px;color:#7AC231">'+(r.court_name||'—')+'</td>'+'<td><span class="badge '+(r.status==='attended'?'badge-green':'badge-grey')+'">'+r.status+'</span></td>'+'</tr>';}).join('')+'</tbody></table>';}catch(e){body.innerHTML='<div style="text-align:center;color:#f87171;padding:24px">Error: '+e.message+'</div>';}}
function closeRegistrations(){document.getElementById('registrationsModal').style.display='none';}
async function setAmbassadorAPI(memberId,enabled){if(!window.ATP||!window.ATP.isLoggedIn())return;try{await window.ATP.admin.setAmbassador(memberId,enabled);console.log('Ambassador updated:',memberId,enabled);}catch(e){console.warn('Ambassador API:',e.message);}}
var LOGO_SRC="/atp-logo-transparent.png";document.getElementById('adminLogo').src=LOGO_SRC;document.getElementById('adminLogoNav').src=LOGO_SRC;
/* ===== admin/showtoast.min.js ===== */
function makeAmbassador(id){if(!id)return;var token=getToken();fetch(ATP_API+'/admin/members/'+id+'/ambassador',{method:'PATCH',headers:{'Content-Type':'application/json','Authorization':'Bearer '+token},body:JSON.stringify({enabled:true})}).then(r=>r.json()).then(function(d){if(d.success||d.member||d.message){showToast('✅ Ambassador activated!');setTimeout(function(){loadMembersAPI();renderAmbassadors&&renderAmbassadors();loadCoaches&&loadCoaches();},300);}else{showToast('❌ '+(d.error||'Failed'),true);}}).catch(function(e){showToast('❌ '+e.message,true);});}
function removeAmbassador(id){var token=getToken();fetch(ATP_API+'/admin/members/'+id+'/ambassador',{method:'PATCH',headers:{'Content-Type':'application/json','Authorization':'Bearer '+token},body:JSON.stringify({enabled:false})}).then(r=>r.json()).then(function(d){if(d.success||d.member||d.message){showToast('✅ Ambassador removed');setTimeout(function(){loadMembersAPI();renderAmbassadors&&renderAmbassadors();loadCoachesSection&&loadCoachesSection();},300);}else{showToast('❌ '+(d.error||'Failed'),true);}});}
async function toggleCoach(id,enable){var token=getToken();try{var res=await fetch(ATP_API+'/admin/members/'+id+'/coach',{method:'PATCH',headers:{'Content-Type':'application/json','Authorization':'Bearer '+token},body:JSON.stringify({enabled:enable})}).then(r=>r.json());if(res.message){showToast(enable?'🎽 Coach activated!':'✅ Coach role removed');renderAmbassadors();loadCoachesSection&&loadCoachesSection();}else{showToast('❌ '+(res.error||'Failed'),true);}}catch(e){showToast('❌ '+e.message,true);}}
function showToast(msg,isError){if(window.ATPComponents&&window.ATPComponents.toast){return window.ATPComponents.toast(msg,isError?'danger':'success');}
var t=document.getElementById('adminToast');if(!t)return;t.textContent=msg;t.style.background=isError?'#2a1010':'#0d1a0a';t.style.color=isError?'#f87171':'#7AC231';t.style.display='block';setTimeout(function(){t.style.display='none';},3000);}
async function loadMembersAPI(){var token=getToken();if(!token)return;var q=(document.getElementById('memberSearch')||{}).value||'';var url=ATP_API+'/admin/members?limit=100'+(q?'&search='+encodeURIComponent(q):'');try{var res=await fetch(url,{headers:{'Authorization':'Bearer '+token}});var data=await res.json();if(!data.members)return;MEMBERS_DATA=data.members;var tbody=document.getElementById('membersTbody');if(!tbody)return;tbody.innerHTML=data.members.map(function(m){var name=((m.first_name||'')+' '+(m.last_name||'')).trim()||'Unknown';var ini=((m.first_name||'?')[0]+(m.last_name||'?')[0]).toUpperCase();var joined=m.joined_at?new Date(m.joined_at).toLocaleDateString('en-GB',{month:'short',year:'numeric'}):'—';var isAmb=m.is_ambassador;return'<tr>'+'<td style="display:flex;align-items:center;gap:10px"><div class="admin-av">'+ini+'</div>'+'<div><div class="admin-member-name">'+name+'</div>'+'<div class="admin-member-email">'+m.member_number+' · '+m.email+'</div></div></td>'+'<td style="color:#555;font-size:12px">'+joined+'</td>'+'<td style="color:#fff;font-size:13px;font-weight:600">'+(m.sessions_count||0)+'</td>'+'<td style="font-size:13px;font-weight:700;color:#7AC231">'+(m.points_balance||0)+'</td>'+'<td><span class="badge '+(isAmb?'badge-green':'badge-grey')+'">'+(isAmb?'Ambassador':'Member')+'</span></td>'+'<td>'+
(isAmb?'<button class="admin-btn" style="font-size:11px;padding:4px 10px" onclick="removeAmbassador(this.dataset.mid)" data-mid="'+m.id+'">Remove Amb.</button>':'<button class="admin-btn" style="font-size:11px;padding:4px 10px" onclick="makeAmbassador(this.dataset.mid)" data-mid="'+m.id+'">Make Amb.</button>')+'</td></tr>';}).join('');var lbl=document.querySelector('#section-members .admin-section-title span');if(lbl)lbl.textContent=data.total.toLocaleString()+' total';}catch(e){console.warn('loadMembersAPI:',e.message);}}
/* ===== admin/challenges.min.js ===== */
var CHALLENGE_EDIT_ID=null;var CHALLENGE_PUBLISH_ON_SAVE=false;function generateBadgeSVG(icon,title){var uid='b'+Math.random().toString(36).substr(2,8);return'<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 120 120" style="width:100%;height:100%;display:block">'+'<defs>'+'<radialGradient id="bg'+uid+'" cx="50%" cy="45%" r="60%">'+'<stop offset="0%" stop-color="#1f3310"/>'+'<stop offset="100%" stop-color="#050505"/>'+'</radialGradient>'+'<linearGradient id="ring'+uid+'" x1="0%" y1="0%" x2="100%" y2="100%">'+'<stop offset="0%" stop-color="#7AC231"/>'+'<stop offset="100%" stop-color="#4a7a1d"/>'+'</linearGradient>'+'</defs>'+'<circle cx="60" cy="60" r="58" fill="url(#bg'+uid+')" stroke="url(#ring'+uid+')" stroke-width="3"/>'+'<circle cx="60" cy="8" r="1.5" fill="#7AC231"/>'+'<circle cx="40" cy="12" r="1" fill="#7AC231" opacity="0.6"/>'+'<circle cx="80" cy="12" r="1" fill="#7AC231" opacity="0.6"/>'+'<text x="60" y="62" text-anchor="middle" font-size="42" dominant-baseline="central">'+(icon||'🏆')+'</text>'+'<rect x="12" y="90" width="96" height="18" fill="#7AC231" rx="2"/>'+'<text x="60" y="100" text-anchor="middle" font-size="7" font-family="Arial Black,Impact,sans-serif" fill="#0a0a0a" font-weight="900" letter-spacing="1.5">ATP CHALLENGE</text>'+'</svg>';}
function handleBadgeUpload(event){var file=event.target.files[0];if(!file)return;if(file.size>2*1024*1024){alert('File too large — max 2MB');return;}
var reader=new FileReader();reader.onload=function(e){var dataUrl=e.target.result;document.getElementById('cBadgeImage').value=dataUrl;document.getElementById('badgePreview').innerHTML='<img src="'+dataUrl+'" style="width:100%;height:100%;object-fit:cover;border-radius:50%">';document.getElementById('badgeUploadInfo').textContent='✅ Using uploaded image: '+file.name;var clr=document.getElementById('clearBadgeBtn');if(clr)clr.style.display='inline-block';};reader.readAsDataURL(file);}
function clearBadgeUpload(){document.getElementById('cBadgeImage').value='';document.getElementById('badgeUpload').value='';document.getElementById('badgeUploadInfo').textContent='';var clr=document.getElementById('clearBadgeBtn');if(clr)clr.style.display='none';regenerateBadge();}
function regenerateBadge(){var icon=document.getElementById('cIcon')?.value||'🏆';var title=document.getElementById('cTitle')?.value||'ATP CHALLENGE';var el=document.getElementById('badgePreview');if(el)el.innerHTML=generateBadgeSVG(icon,title);}
function updateDeviceMetric(){var metric=document.getElementById('cMetric')?.value;var dm=document.getElementById('cDeviceMetric');if(!dm)return;var map={km:'km',steps:'steps',calories:'calories',minutes:'heart_rate_minutes'};if(map[metric])dm.value=map[metric];regenerateBadge();}
async function saveChallenge(publish){CHALLENGE_PUBLISH_ON_SAVE=!!publish;var msgEl=document.getElementById('challengeFormMsg');var title=document.getElementById('cTitle')?.value.trim();var icon=document.getElementById('cIcon')?.value||'🏆';var ctype=document.getElementById('cType')?.value;var metric=document.getElementById('cMetric')?.value;var target=parseInt(document.getElementById('cTarget')?.value)||0;var points=parseInt(document.getElementById('cPoints')?.value)||0;var startDate=document.getElementById('cStartDate')?.value;var endDate=document.getElementById('cEndDate')?.value;var desc=document.getElementById('cDesc')?.value.trim();var cityId=document.getElementById('cCity')?.value||null;var device=document.getElementById('cDeviceMetric')?.value||null;if(!title||!ctype||!metric||!target||!startDate||!endDate){msgEl.textContent='⚠️ Title, Type, Metric, Target and Dates are required.';msgEl.style.cssText='display:block;background:#2a1010;color:#f87171;padding:10px 14px;border-radius:8px;margin-bottom:16px;font-size:13px';return;}
var uploadedBadge=document.getElementById('cBadgeImage')?.value;var badgeSvg=uploadedBadge||document.getElementById('badgePreview')?.innerHTML||null;var payload={title,icon,challenge_type:ctype,metric,target,unit:metric,points_reward:points,starts_at:startDate+'T00:00:00Z',ends_at:endDate+'T23:59:59Z',description:desc,city_id:cityId,device_metric:device,badge_svg:badgeSvg,badge_image:uploadedBadge||null};var token=getToken();var btn=document.getElementById('challengeSubmitLabel');if(btn)btn.textContent='⏳ Saving...';try{var url=CHALLENGE_EDIT_ID?ATP_API+'/challenges/'+CHALLENGE_EDIT_ID:ATP_API+'/challenges';var method=CHALLENGE_EDIT_ID?'PATCH':'POST';var res=await fetch(url,{method,headers:{'Content-Type':'application/json','Authorization':'Bearer '+token},body:JSON.stringify(payload)});var data=await res.json();if(data.challenge){if(publish&&!data.challenge.is_published){await fetch(ATP_API+'/challenges/'+data.challenge.id+'/publish',{method:'PATCH',headers:{'Authorization':'Bearer '+token}});}
msgEl.textContent=publish?'✅ Challenge published!':'✅ Challenge saved as draft.';msgEl.style.cssText='display:block;background:#0d1a0a;color:#7AC231;padding:10px 14px;border-radius:8px;margin-bottom:16px;font-size:13px';resetChallengeForm();loadChallengesList();}else{throw new Error(data.error||'Failed');}}catch(e){msgEl.textContent='❌ '+e.message;msgEl.style.cssText='display:block;background:#2a1010;color:#f87171;padding:10px 14px;border-radius:8px;margin-bottom:16px;font-size:13px';}finally{if(btn)btn.textContent='＋ Save as Draft';}}
function saveAndPublish(){saveChallenge(true);}
function resetChallengeForm(){CHALLENGE_EDIT_ID=null;['cTitle','cDesc','cTarget','cPoints','cStartDate','cEndDate'].forEach(function(id){var el=document.getElementById(id);if(el)el.value='';});document.getElementById('cIcon').value='🏆';document.getElementById('challengeFormTitle').textContent='Create New Challenge';document.getElementById('challengeSubmitLabel').textContent='＋ Save as Draft';document.getElementById('cancelChallengeBtn').style.display='none';regenerateBadge();}
function cancelEditChallenge(){resetChallengeForm();}
async function togglePublish(id){var token=getToken();var res=await fetch(ATP_API+'/challenges/'+id+'/publish',{method:'PATCH',headers:{'Authorization':'Bearer '+token}});var d=await res.json();showToast(d.published?'✅ Published!':'⏸ Unpublished');loadChallengesList();}
async function loadChallengesList(){var container=document.getElementById('challengesList');var countEl=document.getElementById('challengeCount');if(!container)return;container.innerHTML='<div style="text-align:center;color:#444;padding:24px">Loading...</div>';try{var token=getToken();var filter=document.getElementById('challengeFilter')?.value||'';var res=await fetch(ATP_API+'/challenges?all=true',{headers:{'Authorization':'Bearer '+token}});var data=await res.json();var challenges=data.challenges||[];if(filter==='published')challenges=challenges.filter(function(c){return c.is_published;});if(filter==='draft')challenges=challenges.filter(function(c){return!c.is_published;});if(countEl)countEl.textContent=challenges.length+' challenges';if(!challenges.length){container.innerHTML='<div style="text-align:center;color:#444;padding:24px">No challenges yet</div>';return;}
container.innerHTML=challenges.map(function(c){var icon=c.icon||'🏆';var badge=c.badge_svg||generateBadgeSVG(icon,c.title);var start=c.starts_at?new Date(c.starts_at).toLocaleDateString('en-GB',{day:'2-digit',month:'short'}):'—';var end=c.ends_at?new Date(c.ends_at).toLocaleDateString('en-GB',{day:'2-digit',month:'short',year:'numeric'}):'—';var isPub=c.is_published;var progress=Math.min(100,Math.round((c.participant_count||0)/(Math.max(1,c.target||1))*100));return'<div class="challenge-card">'+'<div class="challenge-badge-mini">'+badge+'</div>'+'<div class="challenge-info">'+'<div class="challenge-title">'+c.title+'</div>'+'<div class="challenge-meta">'+start+' → '+end+' · 🎯 '+c.target+' '+c.unit+' · 👥 '+c.participant_count+' joined · 🏅 '+c.points_reward+' pts</div>'+
(c.device_metric?'<div style="font-size:10px;color:#7AC231;margin-top:3px">📡 Smart device: '+c.device_metric+'</div>':'')+'<div class="challenge-progress-bar"><div class="challenge-progress-fill" style="width:'+progress+'%"></div></div>'+'</div>'+'<div style="display:flex;flex-direction:column;align-items:flex-end;gap:8px;flex-shrink:0">'+'<span class="pub-badge '+(isPub?'published':'draft')+'">'+(isPub?'PUBLISHED':'DRAFT')+'</span>'+'<div style="display:flex;gap:6px">'+'<button class="admin-btn" style="font-size:11px;padding:4px 10px" onclick="togglePublish(this.dataset.id)" data-id="'+c.id+'">'+(isPub?'⏸ Unpublish':'▶ Publish')+'</button>'+'<button class="admin-btn" style="font-size:11px;padding:4px 10px" onclick="viewLeaderboard(this.dataset.id)" data-id="'+c.id+'">🏆 Board</button>'+'</div>'+'</div>'+'</div>';}).join('');}catch(e){container.innerHTML='<div style="text-align:center;color:#f87171;padding:24px">Error: '+e.message+'</div>';}}
async function viewLeaderboard(challengeId){var challengeTitle=SESSIONS_CACHE[challengeId]?.name||challengeId;var modal=document.getElementById('leaderboardModal');var body=document.getElementById('leaderboardBody');var title=document.getElementById('lbTitle');title.textContent='🏆 '+challengeTitle;modal.style.display='flex';body.innerHTML='<div style="text-align:center;color:#444;padding:24px">Loading...</div>';try{var token=getToken();var res=await fetch(ATP_API+'/challenges/'+challengeId+'/leaderboard',{headers:{'Authorization':'Bearer '+token}});var data=await res.json();var lb=data.leaderboard||[];if(!lb.length){body.innerHTML='<div style="text-align:center;color:#444;padding:24px">No participants yet</div>';return;}
var medals=['🥇','🥈','🥉'];body.innerHTML='<div style="margin-bottom:12px;font-size:12px;color:#555">'+lb.length+' participants</div>'+
lb.map(function(r,i){var name=r.first_name+' '+r.last_name;var pct=r.progress||0;return'<div style="display:flex;align-items:center;gap:12px;padding:10px 0;border-bottom:1px solid #1a1a1a">'+'<div style="width:28px;text-align:center;font-size:16px">'+(medals[i]||'#'+r.rank)+'</div>'+'<div style="flex:1">'+'<div style="font-weight:700;font-size:13px;color:#fff">'+name+'</div>'+'<div style="font-size:11px;color:#555">'+r.member_number+'</div>'+'</div>'+'<div style="text-align:right">'+'<div style="font-family:var(--ff-display);font-size:18px;font-weight:900;color:#7AC231">'+pct+'</div>'+'<div style="font-size:10px;color:#555">progress</div>'+'</div>'+
(r.completed?'<div style="font-size:18px">✅</div>':'')+'</div>';}).join('');}catch(e){body.innerHTML='<div style="text-align:center;color:#f87171;padding:24px">'+e.message+'</div>';}}
/* ===== admin/coaches.min.js ===== */
