async function toggleCoachFeature(){if(!CURRENT_COACH_ID)return;var token=getToken();var res=await fetch(ATP_API+'/coaches/'+CURRENT_COACH_ID,{headers:{'Authorization':'Bearer '+token}});var data=await res.json();var newFeatured=!data.coach.is_featured;await fetch(ATP_API+'/coaches/'+CURRENT_COACH_ID,{method:'PUT',headers:{'Content-Type':'application/json','Authorization':'Bearer '+token},body:JSON.stringify({is_featured:newFeatured})});showToast(newFeatured?'⭐ Coach featured!':'✅ Feature removed');openCoachModal(CURRENT_COACH_ID);loadCoachesSection();}
/* ===== admin/analytics.min.js ===== */
async function loadDashboardAPI(){return loadDashboardWidgets();}
async function loadDashboardWidgets(){try{var token=getToken();var data=await fetch(ATP_API+'/analytics/overview',{headers:{'Authorization':'Bearer '+token}}).then(r=>r.json());var m=data.members||{};var s=data.sessions||{};var statMembers=document.getElementById('stat-members');var statSessions=document.getElementById('stat-sessions');var statAmbs=document.getElementById('stat-ambassadors');var statAtt=document.getElementById('stat-attendance');if(statMembers)statMembers.textContent=(parseInt(m.total)||0).toLocaleString();if(statSessions)statSessions.textContent=(parseInt(s.this_month)||0).toLocaleString();if(statAmbs)statAmbs.textContent=(parseInt(m.ambassadors)||0).toLocaleString();if(statAtt&&s.completed>0)statAtt.textContent='—';try{var recent=await fetch(ATP_API+'/sessions?status=completed&limit=3',{headers:{'Authorization':'Bearer '+token}}).then(r=>r.json());var recentList=recent.sessions||[];var sections=document.querySelectorAll('.admin-section');sections.forEach(function(sec){var title=sec.querySelector('.admin-section-title');if(title&&title.textContent.includes('Recent Sessions Attendance')){var body=sec.querySelector('.admin-section-body');if(body){if(!recentList.length){body.innerHTML='<div style="text-align:center;color:#444;padding:28px;font-size:13px;font-style:italic">No completed sessions yet. Completed sessions will appear here with attendance stats.</div>';}else{body.innerHTML=recentList.map(function(ss){var dt=ss.scheduled_at?new Date(ss.scheduled_at).toLocaleDateString('en-GB',{weekday:'short',day:'2-digit',month:'short'}):'—';var att=parseInt(ss.checkins_count)||0;var cap=parseInt(ss.capacity)||1;var pct=Math.min(100,Math.round((att/cap)*100));return'<div style="margin-bottom:14px">'+'<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px">'+'<div><div style="font-weight:700;font-size:14px">'+ss.name+' · '+dt+'</div><div style="font-size:11px;color:#555">'+(ss.location||'')+'</div></div>'+'<div style="text-align:right"><div style="font-family:var(--ff-display);font-size:18px;font-weight:900;color:#7AC231">'+att+'/'+cap+'</div><div style="font-size:10px;color:#555">checked in</div></div>'+'</div>'+'<div style="height:6px;background:#1a1a1a;border-radius:3px"><div style="width:'+pct+'%;height:100%;background:#7AC231;border-radius:3px"></div></div>'+'</div>';}).join('');}}}});}catch(e){}
var growth=data.growth||[];var chart=document.getElementById('dashGrowthChart');if(chart){if(!growth.length){chart.innerHTML='<div style="color:#333;font-size:12px;margin:auto">No data yet</div>';}else{var maxCount=Math.max.apply(null,growth.map(function(g){return g.count;}))||1;chart.innerHTML=growth.map(function(g){var h=Math.max(8,Math.round((g.count/maxCount)*150));return'<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:4px">'+'<div style="font-size:10px;color:#7AC231;font-weight:700">'+g.count+'</div>'+'<div style="width:100%;background:linear-gradient(to top,#7AC231,#4a7a1d);border-radius:3px 3px 0 0;height:'+h+'px"></div>'+'<div style="font-size:9px;color:#444;white-space:nowrap">'+g.month+'</div>'+'</div>';}).join('');}}
var top=data.top_members||[];var tm=document.getElementById('dashTopMembers');if(tm){if(!top.length){tm.innerHTML='<div style="color:#333;font-size:12px">No data yet</div>';}else{var medals=['🥇','🥈','🥉'];tm.innerHTML=top.slice(0,5).map(function(m,i){return'<div style="display:flex;align-items:center;gap:10px;padding:8px 0;border-bottom:1px solid #111">'+'<div style="width:24px;text-align:center;font-size:14px">'+(medals[i]||'#'+(i+1))+'</div>'+'<div style="flex:1"><div style="font-size:13px;font-weight:600;color:#fff">'+m.first_name+' '+m.last_name+'</div><div style="font-size:11px;color:#555">'+m.member_number+(m.is_ambassador?' · Ambassador':'')+'</div></div>'+'<div style="font-family:var(--ff-display);font-size:16px;font-weight:900;color:#7AC231">'+m.points_balance+'</div>'+'</div>';}).join('');}}}catch(e){console.warn('Dashboard widgets error:',e.message);}}
async function loadAnalytics(){try{var token=getToken();var[overview,demographics]=await Promise.all([fetch(ATP_API+'/analytics/overview',{headers:{'Authorization':'Bearer '+token}}).then(r=>r.json()),fetch(ATP_API+'/analytics/members',{headers:{'Authorization':'Bearer '+token}}).then(r=>r.json()),]);var m=overview.members||{};var s=overview.sessions||{};var ch=overview.challenges||{};var kpis={'kpi-members':[m.total||0,'Total Members'],'kpi-new':[m.new_this_month||0,'New This Month'],'kpi-sessions':[s.total||0,'Total Sessions'],'kpi-ambassadors':[m.ambassadors||0,'Active Coaches'],'kpi-points':[(parseInt(m.total_points)||0).toLocaleString(),'Total Points'],'kpi-challenges':[ch.active||0,'Active Challenges'],};Object.entries(kpis).forEach(function([id,[val]]){var el=document.getElementById(id);if(el)el.querySelector('.kpi-val').textContent=val;});var growth=overview.growth||[];var maxCount=Math.max.apply(null,growth.map(function(g){return g.count;}))||1;document.getElementById('growthChart').innerHTML=growth.map(function(g){var h=Math.max(8,Math.round((g.count/maxCount)*180));return'<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:4px">'+'<div style="font-size:10px;color:#7AC231;font-weight:700">'+g.count+'</div>'+'<div style="width:100%;background:#7AC231;border-radius:3px 3px 0 0;transition:height .5s" style="height:'+h+'px"></div>'+'<div style="font-size:9px;color:#444;white-space:nowrap">'+g.month+'</div>'+'</div>';}).join('')||'<div style="color:#333;font-size:12px">No data yet</div>';growth.forEach(function(g,i){var bars=document.getElementById('growthChart').children;if(bars[i]){var bar=bars[i].children[1];if(bar)bar.style.height=Math.max(8,Math.round((g.count/maxCount)*180))+'px';}});var top=overview.top_members||[];document.getElementById('topMembersList').innerHTML=top.map(function(m,i){var medals=['🥇','🥈','🥉'];return'<div style="display:flex;align-items:center;gap:10px;padding:8px 0;border-bottom:1px solid #111">'+'<div style="width:24px;text-align:center;font-size:14px">'+(medals[i]||'#'+(i+1))+'</div>'+'<div style="flex:1">'+'<div style="font-size:13px;font-weight:600;color:#fff">'+m.first_name+' '+m.last_name+'</div>'+'<div style="font-size:11px;color:#555">'+m.member_number+(m.is_ambassador?' · Ambassador':'')+'</div>'+'</div>'+'<div style="font-family:var(--ff-display);font-size:16px;font-weight:900;color:#7AC231">'+m.points_balance+'</div>'+'</div>';}).join('')||'<div style="color:#333;font-size:12px;padding:12px 0">No data yet</div>';var nats=demographics.nationality||[];var maxNat=Math.max.apply(null,nats.map(function(n){return n.count;}))||1;document.getElementById('nationalityList').innerHTML=nats.slice(0,10).map(function(n){var pct=Math.round((n.count/maxNat)*100);return'<div style="margin-bottom:10px">'+'<div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:4px">'+'<span style="color:#ccc">'+n.nationality+'</span>'+'<span style="color:#7AC231;font-weight:700">'+n.count+'</span>'+'</div>'+'<div style="height:4px;background:#1a1a1a;border-radius:2px">'+'<div style="width:'+pct+'%;height:100%;background:#7AC231;border-radius:2px"></div>'+'</div>'+'</div>';}).join('')||'<div style="color:#333;font-size:12px">No data yet</div>';var cats=overview.activity_breakdown||[];var catNames={regular:'🏃 Regular',social:'🎉 Social',team_sports:'🏆 Team Sports'};var maxCat=Math.max.apply(null,cats.map(function(c){return c.count;}))||1;document.getElementById('sessionCategoryChart').innerHTML=cats.map(function(c){var pct=Math.round((c.count/maxCat)*100);return'<div style="margin-bottom:12px">'+'<div style="display:flex;justify-content:space-between;font-size:12px;margin-bottom:4px">'+'<span style="color:#ccc">'+(catNames[c.session_category]||c.session_category)+'</span>'+'<span style="color:#7AC231;font-weight:700">'+c.count+' sessions</span>'+'</div>'+'<div style="height:6px;background:#1a1a1a;border-radius:3px">'+'<div style="width:'+pct+'%;height:100%;background:#7AC231;border-radius:3px"></div>'+'</div>'+'</div>';}).join('')||'<div style="color:#333;font-size:12px">No sessions yet</div>';}catch(e){console.warn('Analytics error:',e.message);}}
/* ===== admin/cms.min.js ===== */
var CMS_SCHEMA={index:{label:'🏠 Homepage',sections:{hero:{label:'Hero Section',desc:'The main banner at the top of the homepage',fields:[{key:'tag',label:'Top Tag',type:'text',default:'Dubai · Al Ain · Muscat'},{key:'headline',label:'Headline (3 lines)',type:'textarea',default:'Never\nTrain\nAlone',hint:'Use \\n for new lines'},{key:'subtitle',label:'Subtitle',type:'textarea',default:'Join the UAE\'s largest free outdoor fitness community.'},{key:'cta_text',label:'Button Text',type:'text',default:'Join Free'},{key:'cta_link',label:'Button Link',type:'text',default:'/sessions.html'},{key:'hero_video',label:'Hero Video URL',type:'video',hint:'Upload a video or paste a URL. Leave empty for no video.'},{key:'hero_image',label:'Hero Image (fallback)',type:'image',hint:'Shown when video is not available'},]},stats:{label:'Hero Stats',desc:'Numbers displayed in the hero section',fields:[{key:'activities_count',label:'Activity Types',type:'text',default:'19'},{key:'coaches_count',label:'Expert Coaches',type:'text',default:'21'},{key:'days_per_week',label:'Days per Week',type:'text',default:'7'},{key:'cost',label:'Cost label',type:'text',default:'AED 0'},]},story:{label:'Our Story',desc:'The founder story section',fields:[{key:'title',label:'Section Title',type:'text',default:'Our Story'},{key:'body',label:'Story Body',type:'textarea',hint:'Main narrative about ATP origins'},{key:'founder_photo',label:'Founders Photo',type:'image',hint:'Fredy + Tatiana photo'},]},member_stories:{label:'Member Stories',desc:'Transformation stories (3 cards)',fields:[{key:'card1_stat',label:'Card 1 · Stat',type:'text',default:'−9 kg'},{key:'card1_name',label:'Card 1 · Name',type:'text',default:'Jay Ashar · Running tribe'},{key:'card1_quote',label:'Card 1 · Quote',type:'textarea',default:'From 84 kg to 75 kg in one year. Three triathlons. Two full marathons. ATP gave me my life back.'},{key:'card2_stat',label:'Card 2 · Stat',type:'text',default:'Spartan'},{key:'card2_name',label:'Card 2 · Name',type:'text',default:'Gwen Gaje · Better tribe'},{key:'card2_quote',label:'Card 2 · Quote',type:'textarea',default:'I joined for free yoga. Today I\'m a Spartan racer.'},{key:'card3_stat',label:'Card 3 · Stat',type:'text',default:'6×/wk'},{key:'card3_name',label:'Card 3 · Name',type:'text',default:'Valentina · Stronger tribe'},{key:'card3_quote',label:'Card 3 · Quote',type:'textarea',default:'ATP is sport and socialising in one. Friends for life.'},]},partner_pitch:{label:'Partner Pitch',desc:'The sponsor/brand partner section',fields:[{key:'title',label:'Title',type:'text',default:'Partner with ATP'},{key:'subtitle',label:'Subtitle',type:'textarea'},{key:'members_count',label:'Stat 1 — Members',type:'text',default:'7,000+'},{key:'sessions_count',label:'Stat 2 — Sessions/Year',type:'text',default:'1,500+'},{key:'cities_count',label:'Stat 3 — Cities',type:'text',default:'3'},{key:'years_count',label:'Stat 4 — Years',type:'text',default:'11'},{key:'cta_email',label:'Contact Email',type:'text',default:'partners@atthepark.world'},]}}},sessions:{label:'📅 Sessions Page',sections:{hero:{label:'Sessions Hero',desc:'Header of the sessions listing page',fields:[{key:'title',label:'Page Title',type:'text',default:'All Sessions'},{key:'subtitle',label:'Subtitle',type:'textarea',default:'Browse and book upcoming ATP sessions across Dubai, Al Ain and Muscat.'},]}}},community:{label:'👥 Community Page',sections:{hero:{label:'Community Hero',desc:'Header of the community page',fields:[{key:'title',label:'Page Title',type:'text',default:'Our Community'},{key:'subtitle',label:'Subtitle',type:'textarea',default:'Meet the 7,000+ members who train with us weekly.'},]}}},store:{label:'🛍 Store Page',sections:{hero:{label:'Store Hero',desc:'Header of the ATP merch store',fields:[{key:'title',label:'Store Title',type:'text',default:'ATP Store'},{key:'subtitle',label:'Subtitle',type:'textarea',default:'Official ATP merchandise — limited drops, 100% reinvested in the community.'},{key:'banner',label:'Top Banner Image',type:'image'},]}}}};var CMS_CURRENT_PAGE='index';var CMS_CONTENT_CACHE={};function selectCmsPage(page){CMS_CURRENT_PAGE=page;document.querySelectorAll('.cms-tab').forEach(function(t){t.classList.toggle('active',t.dataset.page===page);});loadContentEditor();}
async function loadContentEditor(){var body=document.getElementById('cmsEditorBody');if(!body)return;body.innerHTML='<div style="text-align:center;color:#444;padding:40px">Loading '+CMS_CURRENT_PAGE+'...</div>';if(CMS_CURRENT_PAGE==='_media'){return loadMediaLibrary();}
try{var token=getToken();var data=await fetch(ATP_API+'/cms/'+CMS_CURRENT_PAGE,{headers:{'Authorization':'Bearer '+token}}).then(r=>r.json());CMS_CONTENT_CACHE[CMS_CURRENT_PAGE]=data.content||{};renderCmsEditor();}catch(e){body.innerHTML='<div style="text-align:center;color:#f87171;padding:40px">Error: '+e.message+'</div>';}}
function renderCmsEditor(){var page=CMS_CURRENT_PAGE;var schema=CMS_SCHEMA[page];var current=CMS_CONTENT_CACHE[page]||{};if(!schema){document.getElementById('cmsEditorBody').innerHTML='<div style="color:#555;padding:40px;text-align:center">No schema defined for this page yet.</div>';return;}
var html='';Object.keys(schema.sections).forEach(function(sectionKey){var section=schema.sections[sectionKey];var sectionData=current[sectionKey]||{};html+='<div class="cms-field-group">'+'<div class="cms-field-group-title">'+section.label+'</div>'+
(section.desc?'<div class="cms-field-group-desc">'+section.desc+'</div>':'');section.fields.forEach(function(field){var current_val=sectionData[field.key]!=null?sectionData[field.key]:(field.default||'');var fieldId='cms_'+page+'_'+sectionKey+'_'+field.key;html+='<div class="cms-field">';html+='<label>'+field.label+'</label>';if(field.type==='textarea'){html+='<textarea id="'+fieldId+'" data-section="'+sectionKey+'" data-key="'+field.key+'" data-type="'+field.type+'">'+String(current_val).replace(/</g,'&lt;')+'</textarea>';}else if(field.type==='image'||field.type==='video'){html+='<div style="display:flex;gap:8px;align-items:start">';html+='<input type="text" id="'+fieldId+'" data-section="'+sectionKey+'" data-key="'+field.key+'" data-type="'+field.type+'" value="'+String(current_val).replace(/"/g,'&quot;')+'" placeholder="URL or data:image/... or click Upload" style="flex:1">';html+='<button class="admin-btn" style="font-size:11px;padding:8px 14px;white-space:nowrap" onclick="openCmsUpload(\''+fieldId+'\',\''+field.type+'\')">📁 Upload</button>';html+='</div>';if(current_val&&String(current_val).length>10){if(field.type==='image'){html+='<img src="'+current_val+'" class="cms-image-preview" onerror="this.style.display=\'none\'">';}else{html+='<video src="'+current_val+'" controls class="cms-image-preview" onerror="this.style.display=\'none\'"></video>';}}}else{html+='<input type="text" id="'+fieldId+'" data-section="'+sectionKey+'" data-key="'+field.key+'" data-type="'+field.type+'" value="'+String(current_val).replace(/"/g,'&quot;')+'">';}
if(field.hint)html+='<div style="font-size:10px;color:#444;margin-top:4px">'+field.hint+'</div>';html+='</div>';});html+='</div>';});html+='<div style="position:sticky;bottom:0;background:#0a0a0a;padding:16px 0;border-top:1px solid #1a1a1a;display:flex;gap:10px;align-items:center;z-index:10">';html+='<button class="admin-btn admin-btn-primary" style="padding:12px 28px;font-size:13px;font-weight:800" data-atp-call="saveCmsContent">✓ Save All Changes</button>';html+='<button class="admin-btn" style="padding:12px 20px;font-size:13px" data-atp-call="loadContentEditor">↻ Revert</button>';html+='<a href="/'+(page==='index'?'':page+'.html')+'" target="_blank" class="admin-btn" style="padding:12px 20px;font-size:13px;text-decoration:none">🔗 Preview Live Page</a>';html+='<span id="cmsSaveMsg" style="margin-left:16px;font-size:12px"></span>';html+='</div>';document.getElementById('cmsEditorBody').innerHTML=html;}
async function saveCmsContent(){var msg=document.getElementById('cmsSaveMsg');msg.textContent='⏳ Saving...';msg.style.color='#888';var inputs=document.querySelectorAll('[id^="cms_'+CMS_CURRENT_PAGE+'_"]');var updates=[];inputs.forEach(function(input){updates.push({page:CMS_CURRENT_PAGE,section:input.dataset.section,key:input.dataset.key,value_text:(input.dataset.type==='text'||input.dataset.type==='textarea')?input.value:null,value_url:(input.dataset.type==='image'||input.dataset.type==='video'||input.dataset.type==='url')?input.value:null,});});try{var token=getToken();var res=await fetch(ATP_API+'/cms/bulk',{method:'PUT',headers:{'Content-Type':'application/json','Authorization':'Bearer '+token},body:JSON.stringify({updates})});var d=await res.json();if(d.message){msg.textContent='✅ Saved — '+updates.length+' fields';msg.style.color='#7AC231';setTimeout(function(){msg.textContent='';},4000);}else{throw new Error(d.error||'Failed');}}catch(e){msg.textContent='❌ '+e.message;msg.style.color='#f87171';}}
var _uploadTargetFieldId=null;function openCmsUpload(fieldId,type){_uploadTargetFieldId=fieldId;document.getElementById('mediaUploadModal').style.display='flex';document.getElementById('cmsFileInput').accept=(type==='video'?'video/*':'image/*');document.getElementById('cmsFileInput').value='';document.getElementById('cmsUploadPreview').innerHTML='';document.getElementById('cmsUploadMsg').textContent='';}
async function handleCmsUpload(event){var file=event.target.files[0];if(!file)return;var msg=document.getElementById('cmsUploadMsg');var preview=document.getElementById('cmsUploadPreview');if(file.size>10*1024*1024){msg.textContent='❌ File too large (max 10MB). Consider compressing it.';msg.style.color='#f87171';return;}
msg.textContent='⏳ Reading file...';msg.style.color='#888';var reader=new FileReader();reader.onload=async function(e){var dataUrl=e.target.result;if(file.type.startsWith('image/')){preview.innerHTML='<img src="'+dataUrl+'" style="max-width:100%;max-height:200px;border-radius:8px">';}else if(file.type.startsWith('video/')){preview.innerHTML='<video src="'+dataUrl+'" controls style="max-width:100%;max-height:200px;border-radius:8px"></video>';}
msg.textContent='⏳ Uploading '+Math.round(file.size/1024)+' KB...';try{var token=getToken();var res=await fetch(ATP_API+'/cms/upload',{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+token},body:JSON.stringify({data_url:dataUrl,filename:file.name,kind:file.type.startsWith('video/')?'video':'image'})});var d=await res.json();if(d.success){msg.textContent='✅ Uploaded ('+d.size_kb+' KB)';msg.style.color='#7AC231';if(_uploadTargetFieldId){var target=document.getElementById(_uploadTargetFieldId);if(target)target.value=d.url;}
setTimeout(function(){document.getElementById('mediaUploadModal').style.display='none';renderCmsEditor();},800);}else{throw new Error(d.error||'Upload failed');}}catch(e){msg.textContent='❌ '+e.message;msg.style.color='#f87171';}};reader.readAsDataURL(file);}
async function loadMediaLibrary(){var body=document.getElementById('cmsEditorBody');try{var token=getToken();var data=await fetch(ATP_API+'/cms/media/list',{headers:{'Authorization':'Bearer '+token}}).then(r=>r.json());var media=data.media||[];if(!media.length){body.innerHTML='<div style="text-align:center;color:#555;padding:60px">'+'<div style="font-size:48px;margin-bottom:12px;opacity:.3">🖼</div>'+'<div style="font-size:14px">No media uploaded yet.</div>'+'<div style="font-size:12px;color:#444;margin-top:6px">Upload images or videos from any editor field to see them here.</div>'+'</div>';return;}
body.innerHTML='<div style="font-size:12px;color:#888;margin-bottom:14px">'+media.length+' files</div>'+'<div class="cms-media-grid">'+
media.map(function(m){var isVideo=m.kind==='video';return'<div class="cms-media-card">'+
(isVideo?'<video src="'+m.url+'" muted></video>':'<img src="'+m.url+'" alt="'+m.filename+'">')+'<button class="cms-media-copy" onclick="copyMediaUrl(this.dataset.u)" data-u="'+m.url+'">Copy URL</button>'+'<div class="cms-media-info">'+m.filename.substring(0,24)+'</div>'+'</div>';}).join('')+'</div>';}catch(e){body.innerHTML='<div style="text-align:center;color:#f87171;padding:40px">Error: '+e.message+'</div>';}}
function copyMediaUrl(url){navigator.clipboard.writeText(url).then(function(){showToast('🔗 URL copied');});}
/* ===== admin/settings.min.js ===== */
function showSettingsTab(tab){['announcements','activities','achievements','config'].forEach(function(t){var pane=document.getElementById('settings-pane-'+t);if(pane)pane.style.display=(t===tab)?'block':'none';});document.querySelectorAll('.settings-tab').forEach(function(b){var match=(b.getAttribute('data-args')||'').indexOf('"'+tab+'"')>=0;b.style.borderBottomColor=match?'#7AC231':'transparent';b.style.color=match?'#fff':'#888';});if(tab==='announcements')loadAnnouncementsAdmin();else if(tab==='activities')loadActivitiesAdmin();else if(tab==='achievements')loadAchievementsAdmin();else if(tab==='config')loadSystemConfig();}
function loadSettingsSection(){showSettingsTab('announcements');}
function loadAnnouncementsAdmin(){fetch(ATP_API+'/announcements/admin',{headers:{'Authorization':'Bearer '+getToken()}}).then(function(r){return r.json();}).then(function(data){renderAnnouncementsAdmin((data&&data.announcements)||[]);}).catch(function(){document.getElementById('announcementsList').innerHTML='<div style="padding:14px;color:#f87171">Failed to load announcements.</div>';});}
function renderAnnouncementsAdmin(list){var el=document.getElementById('announcementsList');if(!el)return;if(!list.length){el.innerHTML='<div style="padding:18px;color:#666;text-align:center">No announcements yet. Create one above.</div>';return;}
el.innerHTML='<table style="width:100%;border-collapse:collapse">'+'<thead><tr style="font-size:11px;color:#666;text-align:left;border-bottom:1px solid #1a1a1a">'+'<th style="padding:10px">Status</th><th style="padding:10px">Kind</th><th style="padding:10px">Message</th>'+'<th style="padding:10px;text-align:right">Priority</th><th style="padding:10px">Window</th><th style="padding:10px"></th>'+'</tr></thead><tbody>'+
list.map(function(a){var msg=(a.message||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');var statusBadge=a.is_active?'<span style="font-size:10px;padding:3px 8px;border-radius:20px;background:rgba(122,194,49,.15);color:#7AC231">Active</span>':'<span style="font-size:10px;padding:3px 8px;border-radius:20px;background:rgba(255,255,255,.06);color:#666">Off</span>';var window_=(a.starts_at||a.ends_at)?(a.starts_at?new Date(a.starts_at).toLocaleDateString('en-GB'):'∞')+' → '+
(a.ends_at?new Date(a.ends_at).toLocaleDateString('en-GB'):'∞'):'Always';return'<tr style="border-bottom:1px solid #111;font-size:13px">'+'<td style="padding:10px">'+statusBadge+'</td>'+'<td style="padding:10px;color:#aaa;font-size:11px">'+(a.kind||'info')+'</td>'+'<td style="padding:10px;color:#fff">'+msg+(a.link_url?' <span style="color:#666;font-size:10px">↗</span>':'')+'</td>'+'<td style="padding:10px;text-align:right;color:#aaa">'+(a.priority||0)+'</td>'+'<td style="padding:10px;color:#888;font-size:11px">'+window_+'</td>'+'<td style="padding:10px;text-align:right">'+'<button class="admin-btn" style="font-size:11px;padding:5px 10px;margin-right:4px" data-atp-call="editAnnouncement" data-args=\'["'+a.id+'"]\'>Edit</button>'+'<button class="admin-btn admin-btn-danger" style="font-size:11px;padding:5px 10px" data-atp-call="deleteAnnouncement" data-args=\'["'+a.id+'"]\'>Delete</button>'+'</td>'+'</tr>';}).join('')+'</tbody></table>';}
function showAnnouncementForm(){document.getElementById('announcementFormWrap').style.display='block';document.getElementById('announcementFormTitle').textContent='New announcement';['anEditId','anMessage','anLink','anPriority','anStarts','anEnds'].forEach(function(id){var el=document.getElementById(id);if(el)el.value=id==='anPriority'?'0':'';});document.getElementById('anKind').value='info';document.getElementById('anActive').checked=true;document.getElementById('anMessage').focus();}
function cancelAnnouncementForm(){document.getElementById('announcementFormWrap').style.display='none';}
function editAnnouncement(e,btn){var id=(btn&&btn.getAttribute('data-args')||'').replace(/[\[\]"]/g,'');fetch(ATP_API+'/announcements/admin',{headers:{'Authorization':'Bearer '+getToken()}}).then(function(r){return r.json();}).then(function(data){var a=((data&&data.announcements)||[]).find(function(x){return x.id===id;});if(!a){showToast('Announcement not found',true);return;}
document.getElementById('announcementFormWrap').style.display='block';document.getElementById('announcementFormTitle').textContent='Edit announcement';document.getElementById('anEditId').value=id;document.getElementById('anMessage').value=a.message||'';document.getElementById('anKind').value=a.kind||'info';document.getElementById('anPriority').value=a.priority||0;document.getElementById('anLink').value=a.link_url||'';document.getElementById('anStarts').value=a.starts_at?new Date(a.starts_at).toISOString().slice(0,16):'';document.getElementById('anEnds').value=a.ends_at?new Date(a.ends_at).toISOString().slice(0,16):'';document.getElementById('anActive').checked=!!a.is_active;});}
function saveAnnouncement(){var id=document.getElementById('anEditId').value;var body={message:document.getElementById('anMessage').value.trim(),kind:document.getElementById('anKind').value,priority:Number(document.getElementById('anPriority').value)||0,link_url:document.getElementById('anLink').value.trim()||null,starts_at:document.getElementById('anStarts').value||null,ends_at:document.getElementById('anEnds').value||null,is_active:document.getElementById('anActive').checked,};if(!body.message){showToast('Message required',true);return;}
var url=id?(ATP_API+'/announcements/admin/'+id):(ATP_API+'/announcements/admin');var method=id?'PATCH':'POST';fetch(url,{method:method,headers:{'Content-Type':'application/json','Authorization':'Bearer '+getToken()},body:JSON.stringify(body),}).then(function(r){return r.json();}).then(function(res){if(res&&res.error){showToast('❌ '+res.error,true);return;}
showToast(id?'✅ Announcement updated':'✅ Announcement created');cancelAnnouncementForm();loadAnnouncementsAdmin();if(window.ATPComponents&&window.ATPComponents.loadTicker)ATPComponents.loadTicker();}).catch(function(e){showToast('❌ '+e.message,true);});}
function deleteAnnouncement(e,btn){if(!confirm('Delete this announcement?'))return;var id=(btn&&btn.getAttribute('data-args')||'').replace(/[\[\]"]/g,'');fetch(ATP_API+'/announcements/admin/'+id,{method:'DELETE',headers:{'Authorization':'Bearer '+getToken()},}).then(function(r){return r.json();}).then(function(){showToast('✅ Announcement deleted');loadAnnouncementsAdmin();if(window.ATPComponents&&window.ATPComponents.loadTicker)ATPComponents.loadTicker();}).catch(function(e){showToast('❌ '+e.message,true);});}
function loadActivitiesAdmin(){fetch(ATP_API+'/activities/admin',{headers:{'Authorization':'Bearer '+getToken()}}).then(function(r){return r.json();}).then(function(data){renderActivitiesAdmin((data&&data.activities)||[]);}).catch(function(){document.getElementById('activitiesList').innerHTML='<div style="padding:14px;color:#f87171">Failed to load activities.</div>';});}
function renderActivitiesAdmin(list){var el=document.getElementById('activitiesList');if(!el)return;if(!list.length){el.innerHTML='<div style="padding:18px;color:#666;text-align:center">No activities yet.</div>';return;}
el.innerHTML='<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(220px,1fr));gap:12px">'+
list.map(function(a){var name=(a.name||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');var icon=a.icon||'🏷️';var border=a.is_active?'rgba(122,194,49,.3)':'rgba(255,255,255,.08)';var op=a.is_active?'1':'.45';return'<div style="background:#0d0d0d;border:1px solid '+border+';border-radius:10px;padding:14px;opacity:'+op+'">'+'<div style="font-size:24px;margin-bottom:8px">'+icon+'</div>'+'<div style="font-size:14px;font-weight:700;margin-bottom:2px">'+name+'</div>'+'<div style="font-size:11px;color:#666;margin-bottom:10px">Order '+(a.sort_order||100)+' · '+(a.is_active?'Active':'Off')+'</div>'+'<div style="display:flex;gap:6px">'+'<button class="admin-btn" style="font-size:11px;padding:5px 10px;flex:1" data-atp-call="editActivity" data-args=\'["'+a.id+'"]\'>Edit</button>'+'<button class="admin-btn admin-btn-danger" style="font-size:11px;padding:5px 10px" data-atp-call="deleteActivity" data-args=\'["'+a.id+'"]\'>×</button>'+'</div>'+'</div>';}).join('')+'</div>';}
function showActivityForm(){document.getElementById('activityFormWrap').style.display='block';document.getElementById('activityFormTitle').textContent='New activity';['actEditId','actName','actIcon'].forEach(function(id){var el=document.getElementById(id);if(el)el.value='';});document.getElementById('actSort').value='100';document.getElementById('actName').focus();}
function cancelActivityForm(){document.getElementById('activityFormWrap').style.display='none';}
function editActivity(e,btn){var id=(btn&&btn.getAttribute('data-args')||'').replace(/[\[\]"]/g,'');fetch(ATP_API+'/activities/admin',{headers:{'Authorization':'Bearer '+getToken()}}).then(function(r){return r.json();}).then(function(data){var a=((data&&data.activities)||[]).find(function(x){return x.id===id;});if(!a){showToast('Activity not found',true);return;}
document.getElementById('activityFormWrap').style.display='block';document.getElementById('activityFormTitle').textContent='Edit activity';document.getElementById('actEditId').value=id;document.getElementById('actName').value=a.name||'';document.getElementById('actIcon').value=a.icon||'';document.getElementById('actSort').value=a.sort_order||100;});}
function saveActivity(){var id=document.getElementById('actEditId').value;var body={name:document.getElementById('actName').value.trim(),icon:document.getElementById('actIcon').value.trim()||null,sort_order:Number(document.getElementById('actSort').value)||100,};if(!body.name){showToast('Name required',true);return;}
var url=id?(ATP_API+'/activities/admin/'+id):(ATP_API+'/activities/admin');var method=id?'PATCH':'POST';fetch(url,{method:method,headers:{'Content-Type':'application/json','Authorization':'Bearer '+getToken()},body:JSON.stringify(body),}).then(function(r){return r.json();}).then(function(res){if(res&&res.error){showToast('❌ '+res.error,true);return;}
showToast(id?'✅ Activity updated':'✅ Activity created');cancelActivityForm();loadActivitiesAdmin();}).catch(function(e){showToast('❌ '+e.message,true);});}
function deleteActivity(e,btn){if(!confirm('Deactivate this activity? (Members who already selected it keep it.)'))return;var id=(btn&&btn.getAttribute('data-args')||'').replace(/[\[\]"]/g,'');fetch(ATP_API+'/activities/admin/'+id,{method:'DELETE',headers:{'Authorization':'Bearer '+getToken()},}).then(function(r){return r.json();}).then(function(){showToast('✅ Activity deactivated');loadActivitiesAdmin();}).catch(function(e){showToast('❌ '+e.message,true);});}
function loadAchievementsAdmin(){fetch(ATP_API+'/achievements/admin',{headers:{'Authorization':'Bearer '+getToken()}}).then(function(r){return r.json();}).then(function(data){renderAchievementsAdmin((data&&data.achievements)||[]);}).catch(function(){document.getElementById('achievementsList').innerHTML='<div style="padding:14px;color:#f87171">Failed to load achievements.</div>';});}
function renderAchievementsAdmin(list){var el=document.getElementById('achievementsList');if(!el)return;if(!list.length){el.innerHTML='<div style="padding:18px;color:#666;text-align:center">No achievements yet.</div>';return;}
el.innerHTML='<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:12px">'+
list.map(function(a){var name=(a.name||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');var desc=(a.description||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');var op=a.is_active?'1':'.45';var border=a.is_active?'rgba(122,194,49,.3)':'rgba(255,255,255,.08)';var iconHtml=a.badge_image_url?'<img src="'+a.badge_image_url+'" style="width:48px;height:48px;object-fit:contain;display:block;margin-bottom:10px">':'<div style="font-size:36px;margin-bottom:8px">'+(a.icon||'🏅')+'</div>';var trigger=(a.criteria_type==='manual')?'Manual':a.criteria_type+' ≥ '+(a.criteria_value||0);return'<div style="background:#0d0d0d;border:1px solid '+border+';border-radius:10px;padding:14px;opacity:'+op+'">'+
iconHtml+'<div style="font-size:13px;font-weight:700;margin-bottom:2px">'+name+'</div>'+'<div style="font-size:11px;color:#888;margin-bottom:8px;line-height:1.5">'+desc+'</div>'+'<div style="display:flex;gap:8px;font-size:10px;color:#aaa;margin-bottom:10px">'+'<span>+'+(a.points_reward||0)+' pts</span>'+'<span>·</span>'+'<span>'+trigger+'</span>'+'<span>·</span>'+'<span>'+(a.unlocked_count||0)+' unlocked</span>'+'</div>'+'<div style="display:flex;gap:6px">'+'<button class="admin-btn" style="font-size:11px;padding:5px 10px;flex:1" data-atp-call="editAchievement" data-args=\'["'+a.id+'"]\'>Edit</button>'+'<button class="admin-btn" style="font-size:11px;padding:5px 10px" data-atp-call="awardAchievementPrompt" data-args=\'["'+a.id+'"]\' title="Manually award to a member">+👤</button>'+'<button class="admin-btn admin-btn-danger" style="font-size:11px;padding:5px 10px" data-atp-call="deleteAchievement" data-args=\'["'+a.id+'"]\'>×</button>'+'</div>'+'</div>';}).join('')+'</div>';}
function showAchievementForm(){document.getElementById('achievementFormWrap').style.display='block';document.getElementById('achievementFormTitle').textContent='New achievement';['achEditId','achName','achDesc','achIcon','achBadge'].forEach(function(id){var el=document.getElementById(id);if(el)el.value='';});document.getElementById('achCriteriaType').value='manual';document.getElementById('achCriteriaValue').value='0';document.getElementById('achPoints').value='0';document.getElementById('achSort').value='100';document.getElementById('achActive').checked=true;document.getElementById('achName').focus();}
function cancelAchievementForm(){document.getElementById('achievementFormWrap').style.display='none';}
function editAchievement(e,btn){var id=(btn&&btn.getAttribute('data-args')||'').replace(/[\[\]"]/g,'');fetch(ATP_API+'/achievements/admin',{headers:{'Authorization':'Bearer '+getToken()}}).then(function(r){return r.json();}).then(function(data){var a=((data&&data.achievements)||[]).find(function(x){return x.id===id;});if(!a){showToast('Achievement not found',true);return;}
document.getElementById('achievementFormWrap').style.display='block';document.getElementById('achievementFormTitle').textContent='Edit achievement';document.getElementById('achEditId').value=id;document.getElementById('achName').value=a.name||'';document.getElementById('achDesc').value=a.description||'';document.getElementById('achIcon').value=a.icon||'';document.getElementById('achBadge').value=a.badge_image_url||'';document.getElementById('achCriteriaType').value=a.criteria_type||'manual';document.getElementById('achCriteriaValue').value=a.criteria_value||0;document.getElementById('achPoints').value=a.points_reward||0;document.getElementById('achSort').value=a.sort_order||100;document.getElementById('achActive').checked=!!a.is_active;});}
function saveAchievement(){var id=document.getElementById('achEditId').value;var body={name:document.getElementById('achName').value.trim(),description:document.getElementById('achDesc').value.trim()||null,icon:document.getElementById('achIcon').value.trim()||null,badge_image_url:document.getElementById('achBadge').value.trim()||null,criteria_type:document.getElementById('achCriteriaType').value,criteria_value:Number(document.getElementById('achCriteriaValue').value)||null,points_reward:Number(document.getElementById('achPoints').value)||0,sort_order:Number(document.getElementById('achSort').value)||100,is_active:document.getElementById('achActive').checked,};if(!body.name){showToast('Name required',true);return;}
var url=id?(ATP_API+'/achievements/admin/'+id):(ATP_API+'/achievements/admin');var method=id?'PATCH':'POST';fetch(url,{method:method,headers:{'Content-Type':'application/json','Authorization':'Bearer '+getToken()},body:JSON.stringify(body),}).then(function(r){return r.json();}).then(function(res){if(res&&res.error){showToast('❌ '+res.error,true);return;}
showToast(id?'✅ Achievement updated':'✅ Achievement created');cancelAchievementForm();loadAchievementsAdmin();}).catch(function(e){showToast('❌ '+e.message,true);});}
function deleteAchievement(e,btn){if(!confirm('Deactivate this achievement? Existing unlocks are preserved.'))return;var id=(btn&&btn.getAttribute('data-args')||'').replace(/[\[\]"]/g,'');fetch(ATP_API+'/achievements/admin/'+id,{method:'DELETE',headers:{'Authorization':'Bearer '+getToken()},}).then(function(r){return r.json();}).then(function(){showToast('✅ Achievement deactivated');loadAchievementsAdmin();}).catch(function(e){showToast('❌ '+e.message,true);});}
function awardAchievementPrompt(e,btn){var id=(btn&&btn.getAttribute('data-args')||'').replace(/[\[\]"]/g,'');var memberInput=prompt('Member ID, member number, or email to award this achievement to:');if(!memberInput)return;fetch(ATP_API+'/admin/members?search='+encodeURIComponent(memberInput.trim())+'&limit=1',{headers:{'Authorization':'Bearer '+getToken()},}).then(function(r){return r.json();}).then(function(data){var m=(data&&data.members&&data.members[0]);if(!m){showToast('Member not found',true);return;}
if(!confirm('Award to '+m.first_name+' '+m.last_name+'?'))return;return fetch(ATP_API+'/achievements/admin/award',{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+getToken()},body:JSON.stringify({member_id:m.id,achievement_id:id}),}).then(function(r){return r.json();}).then(function(res){if(res&&res.error){showToast('❌ '+res.error,true);return;}
showToast(res.awarded?('✅ Awarded to '+m.first_name):'Already had it');loadAchievementsAdmin();});}).catch(function(e){showToast('❌ '+e.message,true);});}
function loadSystemConfig(){fetch(ATP_API+'/admin/system-config',{headers:{'Authorization':'Bearer '+getToken()}}).then(function(r){return r.json();}).then(function(data){renderSystemConfig((data&&data.config)||[]);}).catch(function(){document.getElementById('configList').innerHTML='<div style="padding:14px;color:#f87171">Failed to load config.</div>';});}
function renderSystemConfig(rows){var el=document.getElementById('configList');if(!el)return;if(!rows.length){el.innerHTML='<div style="padding:18px;color:#666;text-align:center">No config keys yet.</div>';return;}
el.innerHTML=rows.map(function(r){var raw=(typeof r.value==='string')?r.value:JSON.stringify(r.value);return'<div style="display:grid;grid-template-columns:1fr 200px auto;gap:12px;padding:14px;border-bottom:1px solid #1a1a1a;align-items:center">'+'<div>'+'<div style="font-size:13px;font-weight:700;color:#fff">'+(r.label||r.key)+'</div>'+'<div style="font-size:11px;color:#666;font-family:monospace;margin-top:2px">'+r.key+'</div>'+
(r.description?'<div style="font-size:11px;color:#888;margin-top:4px;line-height:1.5">'+r.description+'</div>':'')+'</div>'+'<input class="admin-form-input" id="cfg-'+r.key+'" value="'+(raw||'').replace(/"/g,'&quot;')+'" style="font-family:monospace;font-size:12px">'+'<button class="admin-btn admin-btn-primary" style="font-size:11px;padding:7px 14px" data-atp-call="saveConfigKey" data-args=\'["'+r.key+'"]\'>Save</button>'+'</div>';}).join('');}
function saveConfigKey(e,btn){var key=(btn&&btn.getAttribute('data-args')||'').replace(/[\[\]"]/g,'');var input=document.getElementById('cfg-'+key);if(!input)return;var raw=input.value.trim();var value;try{value=JSON.parse(raw);}catch(e){value=raw;}
fetch(ATP_API+'/admin/system-config/'+encodeURIComponent(key),{method:'PATCH',headers:{'Content-Type':'application/json','Authorization':'Bearer '+getToken()},body:JSON.stringify({value:value}),}).then(function(r){return r.json();}).then(function(res){if(res&&res.error){showToast('❌ '+res.error,true);return;}
showToast('✅ Saved: '+key);}).catch(function(e){showToast('❌ '+e.message,true);});}
